/**
 * CODE NODE: TÍNH TOÁN (PHIÊN BẢN TRUY XUẤT TRỰC TIẾP - SIÊU ỔN ĐỊNH)
 */
const input = $input.item.json;
const isAuto = input.is_auto === true;

// Lấy dữ liệu dự phòng trực tiếp từ các node nguồn để tránh node trung gian làm mất dữ liệu
let sourceData = {};
try {
    if (isAuto) {
        sourceData = $("Lấy DS Phòng Đang Thuê").item.json;
    } else {
        sourceData = $("Webhook (Chốt tay)1").item.json;
    }
} catch (e) {
    sourceData = {};
}

function getV(key) {
    let b = input.body || sourceData.body;
    if (typeof b === 'string') {
        try { b = JSON.parse(b); } catch (e) { b = null; }
    }

    const targets = [
        input,           // Ưu tiên 1: Node hiện tại
        sourceData,      // Ưu tiên 2: Node nguồn (Gốc)
        b,               // Ưu tiên 3: Body của node hiện tại/nguồn
        sourceData.body, 
        b?.body,
        input.query,
        input.params
    ];

    for (const t of targets) {
        if (t && t[key] !== undefined && t[key] !== null) return t[key];
    }
    return null;
}

// Trích xuất các trường quan trọng
const phong = getV('phong') || getV('ma_phong') || "?";
const hoTen = getV('hoTen') || getV('ho_ten') || "Khách hàng";
const email = getV('email') || "clm@example.com";
const thangNam = getV('thangNam') || getV('thang_nam') || "tháng sau";

let baseRent = 0;
let tongTuReact = Number(getV('tongTien') || getV('tong_tien') || 0);
let rentTuPostgres = Number(getV('tienPhong') || getV('tien_phong') || 0);

if (isAuto) {
    baseRent = rentTuPostgres;
} else {
    baseRent = tongTuReact;
}

let val_dien, val_nuoc;
if (isAuto) {
    val_dien = 1000;
    val_nuoc = 1000;
} else {
    const sd = Number(getV('chiSoDienMoi') || 0) - Number(getV('chiSoDienCu') || 0);
    const sn = Number(getV('chiSoNuocMoi') || 0) - Number(getV('chiSoNuocCu') || 0);
    val_dien = Math.max(0, sd * 1000);
    val_nuoc = Math.max(0, sn * 1000);
}

const finalTotal = (!isAuto && tongTuReact > 0) ? tongTuReact : (baseRent + val_dien + val_nuoc);
const fmt = (v) => new Intl.NumberFormat('vi-VN').format(v) + ' đ';

return {
    json: {
        phong, hoTen, email,
        is_auto: isAuto,
        val_phong: isAuto ? baseRent : (finalTotal - val_dien - val_nuoc),
        val_tong: finalTotal,
        txt_phong: fmt(isAuto ? baseRent : (finalTotal - val_dien - val_nuoc)),
        txt_tong: fmt(finalTotal),
        thangDisplay: thangNam,
        qrUrl: `https://img.vietqr.io/image/MB-0905881525-compact2.png?amount=${finalTotal}&addInfo=ThanhToan_P${phong}&accountName=HUYNH%20NGOC%20HUY`,
        chi_so_dien_cu: Number(getV('chiSoDienCu') || getV('chi_so_dien_cu') || 0),
        chi_so_dien_moi: Number(getV('chiSoDienMoi') || getV('chi_so_dien_moi') || 0),
        chi_so_nuoc_cu: Number(getV('chiSoNuocCu') || getV('chi_so_nuoc_cu') || 0),
        chi_so_nuoc_moi: Number(getV('chiSoNuocMoi') || getV('chi_so_nuoc_moi') || 0)
    }
};

const d = $json;
const html = `<html><body><h2>Hóa đơn P.${d.phong}</h2><p>Tổng: ${d.txt_tong}</p></body></html>`;
return {
  json: d,
  binary: {
    indexHtml: await this.helpers.prepareBinaryData(Buffer.from(html), 'index.html', 'text/html')
  }
};

/**
 * NODE 5: ĐÓNG GÓI PDF
 */
const fileBuffer = await this.helpers.getBinaryDataBuffer(0, 'data');
const pdfBase64 = fileBuffer.toString('base64');
const info = $('2. Tính Toán & VietQR').item.json;

return {
  json: { ...info, pdfBase64 },
  binary: {
    data: await this.helpers.prepareBinaryData(fileBuffer, `HoaDon_P${info.phong}.pdf`, 'application/pdf')
  }
};

